solution_code:
#include <iostream>
#include <string>
#include <vector>

struct Player {
    std::string name;
};

class Team {
    std::vector<Player*> members;
public:
    void addPlayer(Player* p) {
        members.push_back(p);
    }
    void printRoster() const {
        std::cout << "Team roster:\n";
        for (const Player* p : members)
            std::cout << p->name << "\n";
    }
};

int main() {
    int n{};
    std::cin >> n;
    std::vector<Player> pool(static_cast<std::size_t>(n));
    for (int i = 0; i < n; ++i)
        std::cin >> pool[static_cast<std::size_t>(i)].name;
    int m{};
    std::cin >> m;
    Team t;
    for (int i = 0; i < m; ++i)
        t.addPlayer(&pool[static_cast<std::size_t>(i)]);
    t.printRoster();
    return 0;
}

