#include <iostream>
#include <string>
#include <vector>

struct Book {
    std::string title;
    Book(const std::string& t) : title{t} {}
};

class Shelf {
    std::vector<Book*> books;
public:
    void add(Book* b) { books.push_back(b); }
    // BUG: deletes pointers it doesn't own
    ~Shelf() {
        for (Book* b : books)
            delete b;  // WRONG — Shelf does not own these
    }
};

int main() {
    int n{};
    std::cin >> n;
    std::vector<Book> library;
    library.reserve(static_cast<std::size_t>(n));
    for (int i = 0; i < n; ++i) {
        std::string t;
        std::cin >> t;
        library.emplace_back(t);
    }
    {
        Shelf s;
        for (auto& b : library)
            s.add(&b);
    } // Shelf destroyed here
    for (const auto& b : library)
        std::cout << b.title << "\n";
    return 0;
}

